const response = $input.item.json;
const prefilled = $('Pre-fill Schema').item.json._prefilled;
const licitacion_id = $('Pre-fill Schema').item.json.licitacion_id;
const nomenclatura = $('Pre-fill Schema').item.json.nomenclatura;

const textBlock = response.content?.find(b => b.type === 'text');

if (!textBlock) {
  return { json: { licitacion_id, nomenclatura, extraction: null, error: 'no_text_block', estado: 'error' } };
}

const wasTruncated = response.stop_reason === 'max_tokens';
let claudeFields = null;
let parseError = null;

try {
  const clean = textBlock.text.replace(/```json|```/g, '').trim();
  claudeFields = JSON.parse(clean);
} catch (e) {
  if (wasTruncated) {
    // Intentar reparar JSON truncado: cerrar llaves/corchetes abiertos
    try {
      let text = textBlock.text.replace(/```json|```/g, '').trim();
      // Contar llaves y corchetes abiertos
      let braces = 0, brackets = 0;
      for (const ch of text) {
        if (ch === '{') braces++;
        else if (ch === '}') braces--;
        else if (ch === '[') brackets++;
        else if (ch === ']') brackets--;
      }
      // Cerrar lo que falta
      text = text.replace(/,\s*$/, ''); // quitar coma final si existe
      text += ']'.repeat(Math.max(0, brackets));
      text += '}'.repeat(Math.max(0, braces));
      claudeFields = JSON.parse(text);
      parseError = 'truncated_repaired';
    } catch (e2) {
      parseError = `truncated_unrepaired: ${e2.message}`;
    }
  } else {
    parseError = e.message;
  }
}

// Deep merge: prefilled tiene prioridad absoluta
function deepMerge(base, override) {
  const result = { ...base };
  for (const key of Object.keys(override || {})) {
    if (override[key] !== null && override[key] !== undefined) {
      result[key] = (
        typeof override[key] === 'object' &&
        !Array.isArray(override[key]) &&
        typeof result[key] === 'object' &&
        result[key] !== null
      )
        ? deepMerge(result[key], override[key])
        : (result[key] !== null && result[key] !== undefined ? result[key] : override[key]);
    }
  }
  return result;
}

const merged = claudeFields ? deepMerge(claudeFields, prefilled) : prefilled;

return {
  json: {
    licitacion_id,
    nomenclatura,
    extraction: merged,
    modelo: 'claude-sonnet-4-6',
    doc_tipo: 'pdf_directo',
    input_tokens: response.usage?.input_tokens,
    output_tokens: response.usage?.output_tokens,
    truncated: wasTruncated,
    parse_error: parseError || null,
    estado: 'pending'
  }
};

