const files = $input.item.json.files;
const prefilled = $('Pre-fill Schema').item.json._prefilled;
const licitacion_id = $('Pre-fill Schema').item.json.licitacion_id;
const nomenclatura = $('Pre-fill Schema').item.json.nomenclatura;

const EXCLUDE = ['tdr', 'expediente', 'partidas', 'presupuesto', 'link', 'enlace', 'anexo'];
const KEYWORDS = ['bases'];

const score = (f) => {
    const name = f.filename.toLowerCase();
    if (EXCLUDE.some(k => name.includes(k))) return -1;
    if (KEYWORDS.some(k => name.includes(k))) return 2;
    if (f.ext === '.pdf' || f.ext === '.docx') return 1;
    return 0;
};

const candidates = files
    .filter(f => ['.pdf', '.docx'].includes(f.ext))
    .map(f => ({ ...f, _score: score(f) }))
    .filter(f => f._score > 0)
    .sort((a, b) => {
        if (b._score !== a._score) return b._score - a._score;
        return a.fileSizeMB - b.fileSizeMB; // menor tamaño gana el desempate
    });

const best = candidates[0];

if (!best) {
    return { json: { skip: true, razon: 'sin_archivo_util_en_archivo' } };
}

return {
  json: {
    ...best,
    licitacion_id,
    nomenclatura,
    exceeds_claude_limit: best.ext === '.pdf' && (best.fileSizeMB > 22),
    _prefilled: prefilled
  }
}
